#!/usr/bin/env python3"""splicing_error_analysis.py多进程处理多个 BAM 文件，参照 GTF 注释统计 novel splicing events 比例。输出统计：  - total splicing events (junction reads)  - annotated / novel junction counts & reads  - novel junction ratio (junction 维度 & reads 维度)  - per-sample summary table + 可选 TSV 详细表使用方式:  python splicing_error_analysis.py -b a.bam b.bam c.bam -g annotation.gtf [options]依赖:  pip install pysam"""import argparseimport sysimport reimport osimport pysamfrom collections import defaultdictfrom multiprocessing import Pool, cpu_countfrom functools import partial# ─────────────────────────────────────────────────────────────# 1. 参数解析# ─────────────────────────────────────────────────────────────def parse_args():    p = argparse.ArgumentParser(        description="多进程多BAM splicing error 统计（GTF-based novel junction）",        formatter_class=argparse.RawDescriptionHelpFormatter,    )    p.add_argument("-b", "--bam", nargs="+", required=True,                   help="输入 BAM 文件列表（空格分隔，需 samtools index）")    p.add_argument("-g", "--gtf", required=True,                   help="参考注释 GTF/GFF3 文件")    p.add_argument("-r", "--region", default=None,                   help="只处理指定区域，格式: chr1 或 chr1:1000-2000")    p.add_argument("-q", "--mapq", type=int, default=0,                   help="最低 mapping quality（default: 0）")    p.add_argument("--min-intron", type=int, default=20,                   help="N cigar 最小长度才算 splice junction（default: 20）")    p.add_argument("--min-reads", type=int, default=1,                   help="junction 最少支持 reads 数（default: 1）")    p.add_argument("-t", "--threads", type=int, default=None,                   help="并行进程数（default: BAM 文件数，最多使用所有 CPU）")    p.add_argument("-o", "--outdir", default=".",                   help="输出目录（default: 当前目录）")    p.add_argument("--no-detail", action="store_true",                   help="不输出各 sample 的详细 junction TSV")    p.add_argument("-v", "--verbose", action="store_true",                   help="打印每个 sample 的 Top novel junctions")    return p.parse_args()# ─────────────────────────────────────────────────────────────# 2. 解析 GTF → known junction set# ─────────────────────────────────────────────────────────────def load_known_junctions(gtf_path, min_intron=20):    """返回 set of (chrom, donor_end, acceptor_start)，忽略 strand 便于匹配。"""    print(f"[INFO] 解析 GTF: {gtf_path}", file=sys.stderr)    is_gff = gtf_path.endswith(".gff") or gtf_path.endswith(".gff3")    transcripts = defaultdict(list)    with open(gtf_path) as f:        for line in f:            if line.startswith("#"):                continue            fields = line.rstrip("\n").split("\t")            if len(fields) < 9 or fields[2] != "exon":                continue            chrom = fields[0]            start = int(fields[3]) - 1   # GTF 1-based → 0-based            end   = int(fields[4])        # GTF inclusive end → half-open            attr  = fields[8]            if is_gff:                m = re.search(r'Parent=([^;]+)', attr)            else:                m = re.search(r'transcript_id "([^"]+)"', attr)            if not m:                continue            tid = m.group(1).split(",")[0]            transcripts[tid].append((chrom, start, end))    known = set()    for exons in transcripts.values():        exons = sorted(exons, key=lambda x: x[1])        for i in range(len(exons) - 1):            c1, s1, e1 = exons[i]            c2, s2, e2 = exons[i + 1]            if c1 != c2:                continue            if s2 - e1 < min_intron:                continue            known.add((c1, e1, s2))   # (chrom, donor, acceptor)    print(f"[INFO] 已知 junctions: {len(known):,}", file=sys.stderr)    return known# ─────────────────────────────────────────────────────────────# 3. 单 BAM 处理（子进程）# ─────────────────────────────────────────────────────────────def process_one_bam(bam_path, known_junctions, region, mapq_min, min_intron, min_reads):    sample = os.path.basename(bam_path).replace(".bam", "")    print(f"[INFO] [{sample}] 开始处理...", file=sys.stderr)    junction_reads = defaultdict(int)    total_reads    = 0    spliced_reads  = 0    fetch_kwargs = {}    if region:        if ":" in region:            chrom, coords = region.split(":", 1)            s, e = coords.replace(",", "").split("-")            fetch_kwargs = {"contig": chrom, "start": int(s) - 1, "end": int(e)}        else:            fetch_kwargs = {"contig": region}    try:        bam = pysam.AlignmentFile(bam_path, "rb")        for read in bam.fetch(**fetch_kwargs):            if read.is_unmapped or read.is_secondary or read.is_supplementary:                continue            if read.mapping_quality < mapq_min:                continue            total_reads += 1            cigar = read.cigartuples            if not cigar:                continue            chrom   = read.reference_name            ref_pos = read.reference_start            read_spliced = False            for op, length in cigar:                if op in (0, 2, 3, 7, 8):   # ops that consume reference                    if op == 3 and length >= min_intron:   # N = intron skip                        junction_reads[(chrom, ref_pos, ref_pos + length)] += 1                        read_spliced = True                    ref_pos += length            if read_spliced:                spliced_reads += 1        bam.close()    except Exception as e:        print(f"[ERROR] [{sample}] {e}", file=sys.stderr)        return None    # ── 分类 ──────────────────────────────────    annotated_junc  = {}    novel_junc      = {}    annotated_reads = 0    novel_reads     = 0    for junc, cnt in junction_reads.items():        if cnt < min_reads:            continue        if junc in known_junctions:            annotated_junc[junc]  = cnt            annotated_reads      += cnt        else:            novel_junc[junc]  = cnt            novel_reads      += cnt    total_junc       = len(annotated_junc) + len(novel_junc)    total_junc_reads = annotated_reads + novel_reads    print(        f"[INFO] [{sample}] 完成 —— "        f"reads={total_reads:,}, spliced={spliced_reads:,}, "        f"junctions={total_junc:,}, novel={len(novel_junc):,}",        file=sys.stderr,    )    return {        "sample"           : sample,        "bam"              : bam_path,        "total_reads"      : total_reads,        "spliced_reads"    : spliced_reads,        "total_junctions"  : total_junc,        "annot_junctions"  : len(annotated_junc),        "novel_junctions"  : len(novel_junc),        "total_junc_reads" : total_junc_reads,        "annot_reads"      : annotated_reads,        "novel_reads"      : novel_reads,        "_annotated_junc"  : annotated_junc,        "_novel_junc"      : novel_junc,    }# ─────────────────────────────────────────────────────────────# 4. 输出# ─────────────────────────────────────────────────────────────def pct(a, b, digits=4):    return f"{a/b*100:.{digits}f}%" if b else "N/A"def print_summary_table(results):    W = 120    col = (        f"{'Sample':<28} {'TotalReads':>12} {'SplicedReads':>13} {'SplicingRatio':>14} "        f"{'TotalJunc':>10} {'AnnotJunc':>10} {'NovelJunc':>10} "        f"{'NovelJuncRatio':>15} {'NovelReadRatio':>15}"    )    print("\n" + "=" * W)    print("  Splicing Error Summary  (Novel Junction Analysis vs GTF)")    print("=" * W)    print(col)    print("─" * W)    for r in results:        print(            f"{r['sample']:<28} "            f"{r['total_reads']:>12,} "            f"{r['spliced_reads']:>13,} "            f"{pct(r['spliced_reads'], r['total_reads']):>14} "            f"{r['total_junctions']:>10,} "            f"{r['annot_junctions']:>10,} "            f"{r['novel_junctions']:>10,} "            f"{pct(r['novel_junctions'], r['total_junctions']):>15} "            f"{pct(r['novel_reads'], r['total_junc_reads']):>15}"        )    print("─" * W)    # 汇总行    def S(k): return sum(r[k] for r in results)    tr, sr  = S("total_reads"), S("spliced_reads")    tj, aj  = S("total_junctions"), S("annot_junctions")    nj      = S("novel_junctions")    tjr, nr = S("total_junc_reads"), S("novel_reads")    print(        f"{'[ALL SAMPLES]':<28} "        f"{tr:>12,} {sr:>13,} {pct(sr,tr):>14} "        f"{tj:>10,} {aj:>10,} {nj:>10,} "        f"{pct(nj,tj):>15} {pct(nr,tjr):>15}"    )    print("=" * W)    print("""  列说明:    TotalReads      — 合格 reads 总数（过滤 unmapped / secondary / low-MAPQ）    SplicedReads    — 含 ≥1 splice junction 的 reads 数    SplicingRatio   — SplicedReads / TotalReads            （整体剪接率）    TotalJunc       — 观察到的 unique junctions 总数（≥ min-reads 支持）    AnnotJunc       — 与 GTF 注释匹配的 junctions    NovelJunc       — 不在 GTF 中的 junctions              （splicing errors）    NovelJuncRatio  — NovelJunc / TotalJunc                （junction 维度 error 率）    NovelReadRatio  — Novel junction reads / 所有 junction reads（reads 维度 error 率）""")def write_summary_tsv(results, outdir):    path = os.path.join(outdir, "splicing_summary.tsv")    header = [        "sample", "bam",        "total_reads", "spliced_reads", "splicing_ratio",        "total_junctions", "annot_junctions", "novel_junctions", "novel_junction_ratio",        "total_junc_reads", "annot_reads", "novel_reads", "novel_read_ratio",    ]    with open(path, "w") as f:        f.write("\t".join(header) + "\n")        for r in results:            f.write("\t".join([                r["sample"], r["bam"],                str(r["total_reads"]),                str(r["spliced_reads"]),                pct(r["spliced_reads"],    r["total_reads"]),                str(r["total_junctions"]),                str(r["annot_junctions"]),                str(r["novel_junctions"]),                pct(r["novel_junctions"],  r["total_junctions"]),                str(r["total_junc_reads"]),                str(r["annot_reads"]),                str(r["novel_reads"]),                pct(r["novel_reads"],      r["total_junc_reads"]),            ]) + "\n")    print(f"[INFO] 汇总表 → {path}", file=sys.stderr)def write_detail_tsv(result, outdir):    path = os.path.join(outdir, f"{result['sample']}.junctions.tsv")    with open(path, "w") as f:        f.write("chrom\tdonor\tacceptor\tintron_size\tread_count\ttype\n")        for (c, d, a), cnt in sorted(                result["_annotated_junc"].items(), key=lambda x: -x[1]):            f.write(f"{c}\t{d}\t{a}\t{a-d}\t{cnt}\tannotated\n")        for (c, d, a), cnt in sorted(                result["_novel_junc"].items(), key=lambda x: -x[1]):            f.write(f"{c}\t{d}\t{a}\t{a-d}\t{cnt}\tnovel\n")    print(f"[INFO] [{result['sample']}] junction 详细表 → {path}", file=sys.stderr)def print_top_novel(result, n=10):    novel = result["_novel_junc"]    if not novel:        print(f"\n  [{result['sample']}] 无 novel junctions。")        return    print(f"\n  [{result['sample']}] Top {n} novel junctions:")    print(f"  {'chrom':<12} {'donor':>12} {'acceptor':>12} {'intron_size':>12} {'reads':>8}")    print(f"  {'-'*12} {'-'*12} {'-'*12} {'-'*12} {'-'*8}")    for (c, d, a), cnt in sorted(novel.items(), key=lambda x: -x[1])[:n]:        print(f"  {c:<12} {d:>12} {a:>12} {a-d:>12,} {cnt:>8}")# ─────────────────────────────────────────────────────────────# 5. 主函数# ─────────────────────────────────────────────────────────────def main():    args = parse_args()    os.makedirs(args.outdir, exist_ok=True)    # 验证输入    for b in args.bam:        if not os.path.exists(b):            print(f"[ERROR] 文件不存在: {b}", file=sys.stderr)            sys.exit(1)        if not (os.path.exists(b + ".bai") or os.path.exists(b.replace(".bam", ".bai"))):            print(f"[WARN] 未找到索引: {b}.bai，请先运行 samtools index {b}",                  file=sys.stderr)    # 主进程解析 GTF（只做一次）    known_junctions = load_known_junctions(args.gtf, args.min_intron)    n_workers = min(        args.threads or len(args.bam),        cpu_count(),        len(args.bam),    )    print(f"[INFO] 启动 {n_workers} 个进程处理 {len(args.bam)} 个 BAM 文件\n",          file=sys.stderr)    worker = partial(        process_one_bam,        known_junctions=known_junctions,        region=args.region,        mapq_min=args.mapq,        min_intron=args.min_intron,        min_reads=args.min_reads,    )    with Pool(processes=n_workers) as pool:        results = pool.map(worker, args.bam)    results = [r for r in results if r is not None]    if not results:        print("[ERROR] 所有 BAM 文件处理失败。", file=sys.stderr)        sys.exit(1)    # 保持原始顺序    order = {b: i for i, b in enumerate(args.bam)}    results.sort(key=lambda r: order.get(r["bam"], 0))    print_summary_table(results)    write_summary_tsv(results, args.outdir)    if not args.no_detail:        for r in results:            write_detail_tsv(r, args.outdir)    if args.verbose:        for r in results:            print_top_novel(r)if __name__ == "__main__":    main()